package com.trademaster.ims.mobile.checkout;import com.trademaster.ims.config.SecurityConfig;import com.trademaster.ims.mobile.auth.security.*;import com.trademaster.ims.mobile.checkout.controller.MobileCheckoutController;import com.trademaster.ims.mobile.checkout.dto.CheckoutDtos.*;import com.trademaster.ims.mobile.checkout.service.MobileCheckoutService;import com.trademaster.ims.mobile.common.exception.MobileExceptionHandler;import com.trademaster.ims.security.*;import jakarta.servlet.*;import org.junit.jupiter.api.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.webmvc.test.autoconfigure.WebMvcTest;import org.springframework.context.annotation.*;import org.springframework.test.context.ContextConfiguration;import org.springframework.test.context.bean.override.mockito.MockitoBean;import org.springframework.test.web.servlet.MockMvc;import java.math.BigDecimal;import java.util.List;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;import static org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors.*;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@WebMvcTest(MobileCheckoutController.class)@Import({SecurityConfig.class,MobileExceptionHandler.class})@ContextConfiguration(classes={MobileCheckoutController.class,SecurityConfig.class,MobileExceptionHandler.class})class MobileCheckoutSecurityTest{@Autowired MockMvc mvc;@MockitoBean MobileCheckoutService service;@MockitoBean UserDetailsServiceImpl users;@MockitoBean JwtUtils jwt;@MockitoBean CustomerAuthTokenFilter filter;@BeforeEach void setup()throws Exception{doAnswer(i->{((FilterChain)i.getArgument(2)).doFilter((ServletRequest)i.getArgument(0),(ServletResponse)i.getArgument(1));return null;}).when(filter).doFilter(any(),any(),any());when(service.account(any())).thenReturn(7L);when(service.listAddresses(7L)).thenReturn(List.of());when(service.deliveryMethods(null,null)).thenReturn(List.of(new DeliveryMethodResponse(1L,"STANDARD","Standard",null,BigDecimal.TEN,3,5,true,null)));}
@Test void deliveryBrowsingIsPublic()throws Exception{mvc.perform(get("/api/mobile/v1/delivery-methods")).andExpect(status().isOk());}@Test void anonymousAddressDenied()throws Exception{mvc.perform(get("/api/mobile/v1/addresses")).andExpect(status().isUnauthorized());}@Test void employeeCheckoutDenied()throws Exception{mvc.perform(post("/api/mobile/v1/checkout/review").with(user("employee").roles("EMPLOYEE")).contentType("application/json").content("{\"addressId\":1,\"deliveryMethodId\":1}")).andExpect(status().isForbidden());}@Test void customerPrincipalOwnsAddressLookup()throws Exception{mvc.perform(get("/api/mobile/v1/addresses").with(authentication(new CustomerAuthentication(7L)))).andExpect(status().isOk());verify(service).listAddresses(7L);}@Test void addressValidationRejectsUnsafeEmptyBody()throws Exception{mvc.perform(post("/api/mobile/v1/addresses").with(authentication(new CustomerAuthentication(7L))).contentType("application/json").content("{}" )).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("VALIDATION_ERROR"));}}
